sp_instance.widget_parameters:
{
	"html": {
		"value": "<div class="health-tips-grid">
<div class="tips-header">
<h2>✨ Health Tips for You</h2>
<p>Simple daily habits for a better life</p>
</div>
<div class="tips-container">
<div class="tip-card">
<div class="tip-emoji">💧</div>
<p class="tip-text">Staying hydrated boosts your energy and mental clarity. Drink at least 8 glasses of water daily!</p>
</div>
<div class="tip-card">
<div class="tip-emoji">🍎</div>
<p class="tip-text">A balanced diet rich in fruits and vegetables strengthens your immune system naturally.</p>
</div>
<div class="tip-card">
<div class="tip-emoji">😴</div>
<p class="tip-text">Quality sleep (7&ndash;8 hours) improves memory, mood, and overall health. Prioritize rest!</p>
</div>
</div>
</div>
<style>
.health-tips-grid {
  background: linear-gradient(135deg, #FFFFFF, #FFF5F5);
  border-radius: 32px;
  padding: 40px 30px;
  margin: 48px 0;
  box-shadow: 0 8px 20px rgba(0,0,0,0.05);
  border: 1px solid #FEE2E2;
}

.tips-header {
  text-align: center;
  margin-bottom: 32px;
}

.tips-header h2 {
  font-size: 28px;
  font-weight: 700;
  color: #0F172A;
  margin-bottom: 8px;
}

.tips-header p {
  font-size: 16px;
  color: #64748B;
}

.tips-container {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
  gap: 24px;
  justify-items: stretch;
}

.tip-card {
  background: white;
  border-radius: 20px;
  padding: 24px 20px;
  text-align: center;
  border: 1px solid #E2E8F0;
  transition: all 0.2s ease;
}

.tip-card:hover {
  transform: translateY(-4px);
  box-shadow: 0 12px 24px rgba(0,0,0,0.08);
  border-color: #E60000;
}

.tip-emoji {
  font-size: 48px;
  margin-bottom: 16px;
  color: #E60000;
}

.tip-text {
  font-size: 15px;
  line-height: 1.5;
  color: #1E293B;
  margin: 0;
}

@media (max-width: 768px) {
  .health-tips-grid {
    padding: 32px 20px;
  }
  .tips-header h2 {
    font-size: 24px;
  }
  .tip-emoji {
    font-size: 40px;
  }
  .tip-text {
    font-size: 14px;
  }
}
</style>",
